#include <stdint.h>

#if !defined(__SOFT_FP__) && defined(__ARM_FP)
  #warning "FPU is not initialized, but the project is compiling for an FPU. Please initialize the FPU before use."
#endif

int main(void)
{
	// RCC Register
	volatile uint32_t *RCC_APB2ENR = (volatile uint32_t *)0x40021018;

	// GPIOA Registers
	volatile uint32_t *GPIOA_CRL = (volatile uint32_t *)0x40010800;
	volatile uint32_t *GPIOA_IDR = (volatile uint32_t *)0x40010808; //input data register
	// Output Data Register (used to select Pull-Up/Pull-Down when PA0 is configured as input)
	volatile uint32_t *GPIOA_ODR = (volatile uint32_t *)0x4001080C;

	// GPIOC Registers
	volatile uint32_t *GPIOC_CRH = (volatile uint32_t *)0x40011004;
	volatile uint32_t *GPIOC_ODR = (volatile uint32_t *)0x4001100C;

	//enabling clock for Port A and C
	*RCC_APB2ENR |= (1<<2);// Port A
	*RCC_APB2ENR |= (1<<4);// Port C

	//or *RCC_APB2ENR |= 0x00000014;

	/*
	 * PA0 is configured as Input Pull-Up/Pull-Down (CNF0 = 10, MODE0 = 00).
	 * In this mode, GPIOA_ODR does NOT drive the pin as an output.
	 * Instead, ODR0 selects the internal resistor:
	 *      ODR0 = 0 --> Internal Pull-Down
	 *      ODR0 = 1 --> Internal Pull-Up
	 * Here we clear Bit0 to enable the internal Pull-Down resistor.
	 */
	*GPIOA_ODR &= 0xFFFFFFFE;

	/*CNF(configuration) is CNF0 and is at bits 2 and 3 and needs to be 0
	bcz here the reset value 0x44444444 so & it with 0xFFFFFFF0 and later the desired config in the CNF0
	same for MODE0 is at bits 0 and 1*/
	*GPIOA_CRL &= 0xFFFFFFF0;

	/*CNF(configuration) is CNF13 and is at bits 22 and 23 and needs to be 0
	bcz here the reset value 0x44444444 so & it with 0xFF0FFFFF and later the desired config in the CNF13
	same for MODE13 is at bits 20 and 21*/
	*GPIOC_CRH &= 0xFF0FFFFF;


	//CNF0 =10 , MODE0= 00 (input pull up or pulldown(decided by the ODR)
	*GPIOA_CRL |= 0x00000008;


	/*CNFy[1:0]: Port x configuration bits (y= 8 .. 15)
	 * In output mode (MODE[1:0] > 00):
	 CNF13 = 00  -> General Purpose Push-Pull

	  MODEy[1:0]: Port x mode bits (y= 8 .. 15)
	  10: Output mode, max speed 2 MHz.
	   so now its 0x44244444 */
	*GPIOC_CRH |= 0x00200000;

	while(1)
	{
		if(((*GPIOA_IDR & 0x00000001) != 0))
		{
	    // Turn LED ON (Blue Pill LED is Active LOW)
	    *GPIOC_ODR &= 0x0000DFFF;
		}

		else
		{
		*GPIOC_ODR |= 0x00002000;
		}
	}




    /* Loop forever */
	for(;;);
}
